export function generateReport(data) {
  // Step 1: Validate input
  if (!data || typeof data !== 'object') {
    throw new Error('Data must be a non-null object');
  }
  if (!Array.isArray(data.entries)) {
    throw new Error('Data must contain an entries array');
  }
  if (!data.title || typeof data.title !== 'string') {
    throw new Error('Data must contain a non-empty title string');
  }
  for (const entry of data.entries) {
    if (typeof entry.name !== 'string' || entry.name.trim() === '') {
      throw new Error('Each entry must have a non-empty name');
    }
    if (typeof entry.value !== 'number' || isNaN(entry.value)) {
      throw new Error('Each entry must have a numeric value');
    }
  }

  // Step 2: Transform data
  const sorted = [...data.entries].sort((a, b) => b.value - a.value);
  const total = sorted.reduce((sum, e) => sum + e.value, 0);
  const avg = sorted.length > 0 ? total / sorted.length : 0;
  const transformed = {
    title: data.title,
    items: sorted.map((e, i) => ({
      rank: i + 1,
      name: e.name.trim(),
      value: e.value,
      percentage: total > 0 ? Math.round((e.value / total) * 100) : 0
    })),
    summary: {
      total: Math.round(total * 100) / 100,
      average: Math.round(avg * 100) / 100,
      count: sorted.length
    }
  };

  // Step 3: Format output
  let output = '=== ' + transformed.title + ' ===\n';
  output += '\n';
  for (const item of transformed.items) {
    output += '#' + item.rank + ' ' + item.name + ': ' + item.value + ' (' + item.percentage + '%)\n';
  }
  output += '\n';
  output += 'Total: ' + transformed.summary.total + '\n';
  output += 'Average: ' + transformed.summary.average + '\n';
  output += 'Count: ' + transformed.summary.count + '\n';

  return output;
}

workspace.tests/report.test.mjs:
import { generateReport } from '../src/reportGenerator.mjs';
import { validateReportData } from '../src/validate.mjs';
import { transformReportData } from '../src/transform.mjs';
import { formatReport } from '../src/format.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

const sampleData = {
  title: 'Sales Report',
  entries: [
    { name: 'Product A', value: 300 },
    { name: 'Product B', value: 150 },
    { name: 'Product C', value: 550 }
  ]
};

// Test 1: full pipeline still works
const report = generateReport(sampleData);
assert(report.includes('=== Sales Report ==='), 'Report should have title header');
assert(report.includes('#1 Product C: 550'), 'Should rank Product C first');
assert(report.includes('#2 Product A: 300'), 'Should rank Product A second');
assert(report.includes('#3 Product B: 150'), 'Should rank Product B third');
assert(report.includes('Total: 1000'), 'Total should be 1000');
assert(report.includes('Count: 3'), 'Count should be 3');

// Test 2: validate rejects bad input
try {
  validateReportData(null);
  assert(false, 'Should throw for null data');
} catch (e) {
  assert(e.message.includes('non-null object'), 'Should mention non-null object: ' + e.message);
}
try {
  validateReportData({ title: 'X' });
  assert(false, 'Should throw for missing entries');
} catch (e) {
  assert(e.message.includes('entries array'), 'Should mention entries array: ' + e.message);
}
try {
  validateReportData({ title: 'X', entries: [{ name: '', value: 1 }] });
  assert(false, 'Should throw for empty name');
} catch (e) {
  assert(e.message.includes('non-empty name'), 'Should mention non-empty name: ' + e.message);
}

// Test 3: transform produces expected structure
const transformed = transformReportData(sampleData);
assert(transformed.title === 'Sales Report', 'Transformed title should match');
assert(transformed.items.length === 3, 'Should have 3 items');
assert(transformed.items[0].rank === 1, 'First item should be rank 1');
assert(transformed.items[0].name === 'Product C', 'First item should be Product C (highest value)');
assert(transformed.items[0].value === 550, 'First item value should be 550');
assert(transformed.items[0].percentage === 55, 'Product C percentage should be 55');
assert(transformed.summary.total === 1000, 'Total should be 1000');
assert(transformed.summary.count === 3, 'Count should be 3');
const expectedAvg = Math.round((1000 / 3) * 100) / 100;
assert(transformed.summary.average === expectedAvg, 'Average should be ' + expectedAvg + ' but got ' + transformed.summary.average);

// Test 4: format returns expected string
const formatted = formatReport(transformed);
assert(typeof formatted === 'string', 'formatReport should return a string');
assert(formatted.includes('=== Sales Report ==='), 'Formatted output should have title');
assert(formatted.includes('#1 Product C: 550 (55%)'), 'Should include formatted first item');
assert(formatted.includes('Total: 1000'), 'Should include total');
assert(formatted.includes('Average: ' + expectedAvg), 'Should include average');

// Test 5: generateReport still composes all three steps
import { readFileSync } from 'node:fs';
const genSource = readFileSync(new URL('../src/reportGenerator.mjs', import.meta.url), 'utf-8');
assert(genSource.includes('import') && (genSource.includes('validate') || genSource.includes('Validate')), 'reportGenerator should import validate module');
assert(genSource.includes('import') && (genSource.includes('transform') || genSource.includes('Transform')), 'reportGenerator should import transform module');
assert(genSource.includes('import') && (genSource.includes('format') || genSource.includes('Format')), 'reportGenerator should import format module');

// Test 6: empty entries
const emptyReport = generateReport({ title: 'Empty', entries: [] });
assert(emptyReport.includes('Total: 0'), 'Empty entries should have Total: 0');
assert(emptyReport.includes('Count: 0'), 'Empty entries should have Count: 0');

console.log('ALL TESTS PASSED');
